def load_posted():
    if POSTED_FILE.exists():
        content = POSTED_FILE.read_text(encoding="utf-8").strip()
        return set(content.splitlines()) if content else set()
    return set()


def save_posted(posted_set):
    POSTED_FILE.write_text("\n".join(sorted(posted_set)), encoding="utf-8")


def send_telegram(text):
    api_url = f"https://api.telegram.org/bot{TELEGRAM_TOKEN}/sendMessage"
    payload = json.dumps({"chat_id": TELEGRAM_CHAT, "text": text}).encode("utf-8")
    req = urllib.request.Request(api_url, data=payload,
                                  headers={"Content-Type": "application/json"})
    try:
        with urllib.request.urlopen(req, timeout=15) as r:
            return json.loads(r.read()).get("ok", False)
    except Exception as e:
        print(f"Ошибка: {e}")
        return False


def main():
    if not TELEGRAM_TOKEN:
        print("TELEGRAM_TOKEN не задан!")
        return

    now = datetime.now(MSK)
    today = now.date()
    posted = load_posted()
    sent = 0

    print(f"[schedule] MSK: {now.strftime('%d.%m.%Y %H:%M')} | отправлено ранее: {len(posted)}")

    for (post_date, post_time, post_id, text) in POSTS:
        if post_id in posted:
            continue
        p_date = date.fromisoformat(post_date)
        p_hour = int(post_time.split(":")[0])
        if today > p_date or (today == p_date and now.hour >= p_hour):
            if send_telegram(text):
                posted.add(post_id)
                save_posted(posted)
                print(f"  ✓ {post_id} отправлен")
                sent += 1
                time.sleep(3)

    print(f"[schedule] отправлено сейчас: {sent}")


if __name__ == "__main__":
    main()
